/**
 * quasicrystalline-physical-clock-bench.ts
 *
 * Microbenchmarks for PhysicalQuasicrystallineClock.
 * Run with: gnode run open-source/gnosis/src/quasicrystalline-physical-clock-bench.ts
 */

import { PhysicalQuasicrystallineClock } from './quasicrystalline-physical-clock';

function bench(label: string, iters: number, fn: () => void): number {
  // warmup
  for (let i = 0; i < Math.min(iters, 1000); i++) fn();
  const start = process.hrtime.bigint();
  for (let i = 0; i < iters; i++) fn();
  const end = process.hrtime.bigint();
  const elapsedNs = Number(end - start);
  const opsPerSec = (iters * 1e9) / elapsedNs;
  console.log(
    `${label.padEnd(40)} ${iters.toString().padStart(10)} iters  ` +
      `${(elapsedNs / 1e6).toFixed(2).padStart(8)} ms  ` +
      `${opsPerSec.toFixed(0).padStart(12)} ops/s`,
  );
  return opsPerSec;
}

function main(): void {
  console.log('PhysicalQuasicrystallineClock — microbenchmarks\n');

  const clock = new PhysicalQuasicrystallineClock({ trajectoryCapacity: 1 << 20 });

  // Baseline: raw Date.now()
  let _sink = 0;
  bench('Date.now() (baseline)', 5_000_000, () => {
    _sink ^= Date.now();
  });

  bench('process.hrtime.bigint() (baseline)', 5_000_000, () => {
    _sink ^= Number(process.hrtime.bigint() & 0xffffn);
  });

  // now()
  const nowOps = bench('PhysicalClock.now()', 1_000_000, () => {
    clock.now();
  });

  // validate()
  const sample = clock.now();
  const valOps = bench('PhysicalClock.validate(reading)', 1_000_000, () => {
    clock.validate(sample);
  });

  console.log('\nSummary');
  console.log('-------');
  console.log(`now()      : ${nowOps.toFixed(0)} ops/s`);
  console.log(`validate() : ${valOps.toFixed(0)} ops/s`);
  console.log(`At ${nowOps.toFixed(0)} ops/s, the clock can be polled at any`);
  console.log('production rate that matters (NTP sync is typically ≤ 1 Hz).');
  void _sink;
}

main();
